import { useState, useEffect } from "react";
import { logoutUser } from "../services/auth";
import { useNavigate } from "react-router-dom";
import { getPolicies } from "../services/firestore";

export default function AgentDashboard() {
  const [searchQuery, setSearchQuery] = useState("");
  const [policies, setPolicies] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchLivePolicies = async () => {
      const data = await getPolicies();
      setPolicies(data);
      setLoading(false);
    };
    fetchLivePolicies();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    navigate("/login");
  };

  const filteredPolicies = policies.filter(policy => {
    const titleMatch = policy.title ? policy.title.toLowerCase().includes(searchQuery.toLowerCase()) : false;
    const contentMatch = policy.content ? policy.content.toLowerCase().includes(searchQuery.toLowerCase()) : false;
    return titleMatch || contentMatch;
  });

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow-sm px-8 py-4 flex justify-between items-center">
        <h1 className="text-xl font-bold text-gray-800">CSR Portal</h1>
        <button 
          onClick={handleLogout}
          className="text-gray-600 hover:text-red-600 font-medium"
        >
          Sign Out
        </button>
      </nav>

      <div className="max-w-4xl mx-auto p-8">
        <h2 className="text-3xl font-bold text-gray-800 mb-8">Knowledge Base</h2>

        <div className="mb-8">
          <input
            type="text"
            placeholder="Search policies..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full p-4 rounded-lg shadow-sm border border-gray-200 focus:outline-none focus:ring-2 focus:ring-blue-500 text-lg"
          />
        </div>

        {loading ? (
          <p className="text-gray-500 text-center py-8">Loading policies...</p>
        ) : (
          <div className="space-y-4">
            {filteredPolicies.map(policy => (
              <div key={policy.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-100">
                <h3 className="text-xl font-semibold text-gray-800 mb-2">{policy.title || "Untitled Policy"}</h3>
                <p className="text-gray-600">{policy.content || "No content available."}</p>
              </div>
            ))}

            {filteredPolicies.length === 0 && (
              <p className="text-gray-500 text-center py-8">No policies found matching your search.</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
